import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const b=JSON.parse('{"title":"증빙 관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/evidence.md","filePath":"guide/scenarios/evidence.md","lastUpdated":null}'),o={name:"guide/scenarios/evidence.md"};function i(n,a,s,h,d,c){return e(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="증빙-관리" tabindex="-1">증빙 관리 <a class="header-anchor" href="#증빙-관리" aria-label="Permalink to &quot;증빙 관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 10분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (거래 발생 시)</p></blockquote><p>아파트뱅크에 연동된 계좌에서 입금이 발생했을 때 수납 미등록 내역을 확인하고, 오류를 해소하여 모든 입금 건이 정상 수납 처리되도록 관리하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 수납 후 미등록 내역 확인  (3분)  → 입금됐지만 수납 미처리된 건 조회</span></span>
<span class="line"><span>2. 입금금액 처리             (3분)  → 미처리 입금을 수납으로 연결</span></span>
<span class="line"><span>3. 수납결과 조회             (2분)  → 처리 결과 확인</span></span>
<span class="line"><span>4. 수납처리 오류 내역 처리   (3분)  → 오류 유형별 해소</span></span>
<span class="line"><span>5. 계좌조회 로그 확인        (수시) → 계좌 조회 문제 발생 시 원인 파악</span></span></code></pre></div><hr><h2 id="사전-이해-빠른계좌-서비스" tabindex="-1">사전 이해: 빠른계좌 서비스 <a class="header-anchor" href="#사전-이해-빠른계좌-서비스" aria-label="Permalink to &quot;사전 이해: 빠른계좌 서비스&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">빠른계좌 서비스 사용 시</p><p>빠른계좌 서비스를 이용하는 단지는 <strong>세대별 가상계좌</strong>로 입금이 자동 처리됩니다. 입금 즉시 수납처리가 완료되고 아파트뱅크에 자동 반영됩니다. 이 경우 수동 처리 건수가 크게 줄어듭니다.</p></div><hr><h2 id="_1단계-수납-후-미등록-내역-확인-3분" tabindex="-1">1단계: 수납 후 미등록 내역 확인 (3분) <a class="header-anchor" href="#_1단계-수납-후-미등록-내역-확인-3분" aria-label="Permalink to &quot;1단계: 수납 후 미등록 내역 확인 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/evidence.html">증빙내역</a> &gt; 수납후미등록내역 (BANK0040)</p></blockquote><p>입금은 되었지만 수납 시스템에 아직 등록되지 않은 건을 조회합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>수납후미등록내역 화면 진입</li><li><strong>조회 기간</strong> 설정</li><li><strong>조회</strong> 실행</li><li>미등록 건 목록 확인: <ul><li>입금 일시</li><li>입금 금액</li><li>입금 계좌</li><li>입금인 (적요)</li><li>처리 상태</li></ul></li></ol><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 오늘 날짜 포함 최근 미등록 건이 있는가?</li><li>[ ] 장기 미처리 건(3일 이상)이 있는가?</li><li>[ ] 금액이 관리비와 일치하지 않는 이상 입금 건이 있는가?</li></ul><hr><h2 id="_2단계-입금금액-처리-3분" tabindex="-1">2단계: 입금금액 처리 (3분) <a class="header-anchor" href="#_2단계-입금금액-처리-3분" aria-label="Permalink to &quot;2단계: 입금금액 처리 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/evidence.html">증빙내역</a> &gt; 입금금액처리 (BANK0050)</p></blockquote><p>미처리 입금 건을 해당 세대의 수납으로 연결합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>입금금액처리 화면 진입</li><li>처리할 미등록 입금 건 선택</li><li>입금 내용(적요, 금액)을 기준으로 <strong>해당 세대</strong> 확인</li><li>세대 동·호수 매칭 후 <strong>수납 처리</strong> 실행</li><li>처리 완료 확인</li></ol><h3 id="입금-관리자-팝업-활용" tabindex="-1">입금 관리자 팝업 활용 <a class="header-anchor" href="#입금-관리자-팝업-활용" aria-label="Permalink to &quot;입금 관리자 팝업 활용&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/evidence.html">증빙내역</a> &gt; 입금관리자팝업 (BANK0060)</p></blockquote><p>입금 건의 세대 식별이 어려울 때 팝업에서 입금 내역 상세 정보를 조회하고 수납 세대를 수동으로 지정합니다.</p><hr><h2 id="_3단계-수납결과-조회-2분" tabindex="-1">3단계: 수납결과 조회 (2분) <a class="header-anchor" href="#_3단계-수납결과-조회-2분" aria-label="Permalink to &quot;3단계: 수납결과 조회 (2분)&quot;">​</a></h2><p>처리한 입금 건이 정상적으로 수납되었는지 확인합니다.</p><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/inquiry.html">수납조회</a></p></blockquote><ol><li>처리 일자 기준으로 수납 내역 조회</li><li>방금 처리한 세대·금액이 수납 목록에 있는지 확인</li><li>이상이 없으면 완료</li></ol><hr><h2 id="_4단계-수납처리-오류-내역-처리-3분" tabindex="-1">4단계: 수납처리 오류 내역 처리 (3분) <a class="header-anchor" href="#_4단계-수납처리-오류-내역-처리-3분" aria-label="Permalink to &quot;4단계: 수납처리 오류 내역 처리 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/evidence.html">증빙내역</a> &gt; 수납처리오류내역 (BANK0090)</p></blockquote><p>자동 수납 처리 중 오류가 발생한 건을 확인하고 해소합니다.</p><h3 id="오류-유형별-해결-방법" tabindex="-1">오류 유형별 해결 방법 <a class="header-anchor" href="#오류-유형별-해결-방법" aria-label="Permalink to &quot;오류 유형별 해결 방법&quot;">​</a></h3><table tabindex="0"><thead><tr><th>오류 유형</th><th>원인</th><th>해결 방법</th></tr></thead><tbody><tr><td><strong>수납동수없음</strong></td><td>입금 세대를 특정할 수 없음</td><td>입금인(적요)으로 세대 확인 후 수동 수납</td></tr><tr><td><strong>금액불일치</strong></td><td>입금액이 고지 금액과 다름</td><td>고지 금액 확인 후 초과분 처리 또는 세대 확인</td></tr><tr><td><strong>납부자미확인</strong></td><td>세대 정보가 없거나 검색 불가</td><td>입금인 연락처 확인 또는 창구 내방 안내</td></tr><tr><td><strong>계좌미등록</strong></td><td>입금 계좌가 단지 계좌에 미등록</td><td>단지 수납 계좌 등록 상태 확인</td></tr></tbody></table><h3 id="오류-건-수동-처리-절차" tabindex="-1">오류 건 수동 처리 절차 <a class="header-anchor" href="#오류-건-수동-처리-절차" aria-label="Permalink to &quot;오류 건 수동 처리 절차&quot;">​</a></h3><ol><li>수납처리오류내역에서 오류 건 확인</li><li>오류 유형 파악 후 위 표 기준으로 조치</li><li>세대 확인 완료 후 <a href="/recp/process.html">수납처리</a>(RECP1010)에서 수동 수납</li><li>처리 결과 재확인</li></ol><div class="warning custom-block"><p class="custom-block-title">미처리 오류 건 방치 금지</p><p>수납처리 오류 건을 방치하면 해당 세대가 미납 상태로 남아 미수금 관리나 고지서 발행에 혼선이 생깁니다. 발생 당일 처리를 원칙으로 하세요.</p></div><hr><h2 id="_5단계-계좌조회-로그-확인-수시" tabindex="-1">5단계: 계좌조회 로그 확인 (수시) <a class="header-anchor" href="#_5단계-계좌조회-로그-확인-수시" aria-label="Permalink to &quot;5단계: 계좌조회 로그 확인 (수시)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/evidence.html">증빙내역</a> &gt; 계좌조회로그 (BANK0080)</p></blockquote><p>은행 거래내역이 조회되지 않거나 연동 오류가 발생할 때 원인을 파악합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>계좌조회로그 화면 진입</li><li>문제 발생 일시 기준으로 조회</li><li>로그 메시지로 원인 파악</li></ol><h3 id="주요-로그-유형" tabindex="-1">주요 로그 유형 <a class="header-anchor" href="#주요-로그-유형" aria-label="Permalink to &quot;주요 로그 유형&quot;">​</a></h3><table tabindex="0"><thead><tr><th>로그 유형</th><th>의미</th><th>조치</th></tr></thead><tbody><tr><td>거래 없음</td><td>해당 기간 입출금 없음</td><td>정상 상태 (조치 불필요)</td></tr><tr><td>인증 오류</td><td>공인인증서 만료 또는 오류</td><td>공인인증서 갱신 후 재시도</td></tr><tr><td>IP 차단</td><td>접속 IP 변경으로 서비스 차단</td><td>아파트뱅크 고객센터에 IP 변경 등록 요청</td></tr><tr><td>은행 점검</td><td>은행 시스템 점검 중</td><td>점검 종료 후 재조회</td></tr></tbody></table><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="입금-건인데-수납이-안-되어-있어요" tabindex="-1">입금 건인데 수납이 안 되어 있어요 <a class="header-anchor" href="#입금-건인데-수납이-안-되어-있어요" aria-label="Permalink to &quot;입금 건인데 수납이 안 되어 있어요&quot;">​</a></h3><p><strong>원인</strong>: 입금인(적요)이 세대와 일치하지 않아 자동 매칭에 실패한 경우입니다. <strong>해결</strong>: 수납후미등록내역(BANK0040)에서 해당 입금 건을 찾아, 입금관리자팝업(BANK0060)으로 세대를 수동 확인한 뒤 입금금액처리(BANK0050)로 연결하세요.</p><h3 id="은행-거래내역이-아파트뱅크에-안-보여요" tabindex="-1">은행 거래내역이 아파트뱅크에 안 보여요 <a class="header-anchor" href="#은행-거래내역이-아파트뱅크에-안-보여요" aria-label="Permalink to &quot;은행 거래내역이 아파트뱅크에 안 보여요&quot;">​</a></h3><p><strong>원인</strong>: 공인인증서 만료, IP 변경, 은행 시스템 점검 등이 원인입니다. <strong>해결</strong>: 계좌조회로그(BANK0080)에서 오류 메시지를 확인하세요. IP 변경이 원인이라면 아파트뱅크 고객센터에 새 IP 등록을 요청해야 합니다.</p><h3 id="금액불일치-오류-건은-어떻게-처리하나요" tabindex="-1">금액불일치 오류 건은 어떻게 처리하나요? <a class="header-anchor" href="#금액불일치-오류-건은-어떻게-처리하나요" aria-label="Permalink to &quot;금액불일치 오류 건은 어떻게 처리하나요?&quot;">​</a></h3><p><strong>원인</strong>: 세대가 고지 금액과 다른 금액을 입금한 경우입니다. <strong>해결</strong>: 고지 금액보다 많이 납부한 경우 초과분을 선납으로 처리하거나 다음 달 차감합니다. 적게 납부한 경우 부족분을 미납으로 남기고 세대에 통보하세요.</p><h3 id="계속-오류-건이-발생하는-특정-세대가-있어요" tabindex="-1">계속 오류 건이 발생하는 특정 세대가 있어요 <a class="header-anchor" href="#계속-오류-건이-발생하는-특정-세대가-있어요" aria-label="Permalink to &quot;계속 오류 건이 발생하는 특정 세대가 있어요&quot;">​</a></h3><p><strong>원인</strong>: 세대 정보(이름, 연락처 등)와 입금 적요가 반복적으로 불일치하는 경우입니다. <strong>해결</strong>: 해당 세대에 납부 시 <strong>세대번호(동·호수) 또는 납부자 성명을 적요에 정확히 기재</strong>하도록 안내하세요. 자동이체 전환을 권장하는 것도 좋습니다.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/bank/evidence.html">수납후미등록내역</a> - 입금 후 수납 미처리 건 조회 (BANK0040)</li><li><a href="/bank/evidence.html">입금금액처리</a> - 미처리 입금 수납 연결 (BANK0050)</li><li><a href="/bank/evidence.html">입금관리자팝업</a> - 세대 수동 확인 팝업 (BANK0060)</li><li><a href="/bank/evidence.html">계좌조회로그</a> - 계좌 연동 오류 로그 (BANK0080)</li><li><a href="/bank/evidence.html">수납처리오류내역</a> - 수납 오류 목록 및 처리 (BANK0090)</li><li><a href="/recp/process.html">수납처리</a> - 수동 수납 처리 (RECP1010)</li><li><a href="/bank/transaction.html">은행거래내역</a> - 계좌 거래 전체 조회 (BANK0010)</li></ul>`,60)])])}const u=t(o,[["render",i]]);export{b as __pageData,u as default};
